comments.body:
with this patch we can drop the fixPerm hack (it should go into https://github.com/containers/storage/pull/172):

```
diff --git a/cmd/podman/spec.go b/cmd/podman/spec.go
index 0e392e8..664a6d5 100644
--- a/cmd/podman/spec.go
+++ b/cmd/podman/spec.go
@@ -68,7 +68,7 @@ func addPidNS(config *createConfig, g *generate.Generator) error {

 func addUserNS(config *createConfig, g *generate.Generator) error {
 	if (len(config.IDMappings.UIDMap) > 0 || len(config.IDMappings.GIDMap) > 0) && !config.UsernsMode.IsHost() {
-		g.AddOrReplaceLinuxNamespace("user", "")
+		g.AddOrReplaceLinuxNamespace(spec.UserNamespace, "")
 	}
 	return nil
 }
diff --git a/libpod/container_internal.go b/libpod/container_internal.go
index 6c98d78..37fa3de 100644
--- a/libpod/container_internal.go
+++ b/libpod/container_internal.go
@@ -593,9 +593,6 @@ func (c *Container) mountStorage() (err error) {
 		if err := os.Chown(c.config.ShmDir, c.RootUID(), c.RootGID()); err != nil {
 			return err
 		}
-		if err := fixPermDir(c.config.ShmDir, c.RootGID()); err != nil {
-			return err
-		}
 	}

 	mountPoint, err := c.runtime.storageService.MountContainerImage(c.ID())
@@ -701,24 +698,6 @@ func (c *Container) cleanup() error {
 	return lastError
 }

-/*
-[FIXME]  We need a way of doing UserNS without having to change the permissions
-all the way up the stack.
-*/
-func fixPermDir(dir string, rootUID int) error {
-	if rootUID != 0 {
-		parent := filepath.Dir(dir)
-		for parent != "/" {
-			err := os.Chmod(parent, 0711)
-			if err != nil {
-				return err
-			}
-			parent = filepath.Dir(parent)
-		}
-	}
-	return nil
-}
-
 // Make standard bind mounts to include in the container
 func (c *Container) makeBindMounts() error {
 	if c.state.BindMounts == nil {
@@ -809,9 +788,6 @@ func (c *Container) writeStringToRundir(destFile, output string) (string, error)
 	if err := f.Chown(c.RootUID(), c.RootGID()); err != nil {
 		return "", err
 	}
-	if err := fixPermDir(destFileName, c.RootUID()); err != nil {
-		return "", err
-	}

 	if _, err := f.WriteString(output); err != nil {
 		return "", errors.Wrapf(err, "unable to write %s", destFileName)
diff --git a/vendor/github.com/containers/storage/drivers/overlay/overlay.go b/vendor/github.com/containers/storage/drivers/overlay/overlay.go
index 463e015..e0d8d30 100644
--- a/vendor/github.com/containers/storage/drivers/overlay/overlay.go
+++ b/vendor/github.com/containers/storage/drivers/overlay/overlay.go
@@ -879,17 +879,22 @@ func (d *Driver) UpdateLayerIDMap(id string, toContainer, toHost *idtools.IDMapp
 	}

 	// Re-create the directory that we're going to use as the upper layer.
-	if err := idtools.MkdirAs(diffDir, 0700, rootUID, rootGID); err != nil {
+	if err := idtools.MkdirAs(diffDir, 0755, rootUID, rootGID); err != nil {
 		return err
 	}

+	// Make sure that host root is the only user that can search through
+	// the container storage directory.
+	if err = os.Chmod(dir, 0700); err != nil {
+		return errors.Wrapf(err, "cannot chmod '%s'", dir)
+	}
+
 	if rootUID != 0 {
+		// If using userns make sure the container dir is owned by
+		// root of the container.
 		if err = os.Chown(dir, rootUID, rootGID); err != nil {
 			return errors.Wrapf(err, "cannot chown '%s'", dir)
 		}
-		if err = os.Chmod(dir, 0700); err != nil {
-			return errors.Wrapf(err, "cannot chmod '%s'", dir)
-		}
 	}
 	return nil
 }
diff --git a/vendor/github.com/containers/storage/store.go b/vendor/github.com/containers/storage/store.go
index 68e3fed..686725a 100644
--- a/vendor/github.com/containers/storage/store.go
+++ b/vendor/github.com/containers/storage/store.go
@@ -540,14 +540,14 @@ func GetStore(options StoreOptions) (Store, error) {
 		return nil, ErrIncompleteOptions
 	}

-	if err := os.MkdirAll(options.RunRoot, 0700); err != nil && !os.IsExist(err) {
+	if err := os.MkdirAll(options.RunRoot, 0711); err != nil && !os.IsExist(err) {
 		return nil, err
 	}
 	if err := os.MkdirAll(filepath.Join(options.GraphRoot, options.GraphDriverName), 0711); err != nil && !os.IsExist(err) {
 		return nil, err
 	}
 	for _, subdir := range []string{"mounts", "tmp", options.GraphDriverName} {
-		if err := os.MkdirAll(filepath.Join(options.GraphRoot, subdir), 0700); err != nil && !os.IsExist(err) {
+		if err := os.MkdirAll(filepath.Join(options.GraphRoot, subdir), 0711); err != nil && !os.IsExist(err) {
 			return nil, err
 		}
 	}
@@ -629,7 +629,7 @@ func (s *store) load() error {
 	}

 	gipath := filepath.Join(s.graphRoot, driverPrefix+"images")
-	if err := os.MkdirAll(gipath, 0700); err != nil {
+	if err := os.MkdirAll(gipath, 0711); err != nil {
 		return err
 	}
 	ris, err := newImageStore(gipath)
@@ -642,7 +642,7 @@ func (s *store) load() error {
 	}

 	gcpath := filepath.Join(s.graphRoot, driverPrefix+"containers")
-	if err := os.MkdirAll(gcpath, 0700); err != nil {
+	if err := os.MkdirAll(gcpath, 0711); err != nil {
 		return err
 	}
 	rcs, err := newContainerStore(gcpath)
@@ -650,7 +650,7 @@ func (s *store) load() error {
 		return err
 	}
 	rcpath := filepath.Join(s.runRoot, driverPrefix+"containers")
-	if err := os.MkdirAll(rcpath, 0700); err != nil {
+	if err := os.MkdirAll(rcpath, 0711); err != nil {
 		return err
 	}
 	s.containerStore = rcs
@@ -2394,11 +2394,22 @@ func (s *store) ContainerDirectory(id string) (string, error) {
 		return "", err
 	}

+	rootUID, rootGID, err := idtools.GetRootUIDGID(s.uidMap, s.gidMap)
+	if err != nil {
+		return "", err
+	}
+
 	middleDir := s.graphDriverName + "-containers"
-	gcpath := filepath.Join(s.GraphRoot(), middleDir, id, "userdata")
-	if err := os.MkdirAll(gcpath, 0700); err != nil {
+	stateDir := filepath.Join(s.GraphRoot(), middleDir)
+	if err := os.MkdirAll(stateDir, 0711); err != nil {
 		return "", err
 	}
+
+	gcpath := filepath.Join(stateDir, id, "userdata")
+	if err := idtools.MkdirAllAs(gcpath, 0700, rootUID, rootGID); err != nil {
+		return "", err
+	}
+
 	return gcpath, nil
 }

@@ -2419,9 +2430,19 @@ func (s *store) ContainerRunDirectory(id string) (string, error) {
 		return "", err
 	}

+	rootUID, rootGID, err := idtools.GetRootUIDGID(s.uidMap, s.gidMap)
+	if err != nil {
+		return "", err
+	}
+
 	middleDir := s.graphDriverName + "-containers"
-	rcpath := filepath.Join(s.RunRoot(), middleDir, id, "userdata")
-	if err := os.MkdirAll(rcpath, 0700); err != nil {
+	runDir := filepath.Join(s.RunRoot(), middleDir)
+	if err := os.MkdirAll(runDir, 0711); err != nil {
+		return "", err
+	}
+
+	rcpath := filepath.Join(runDir, id, "userdata")
+	if err := idtools.MkdirAllAs(rcpath, 0700, rootUID, rootGID); err != nil {
 		return "", err
 	}
 	return rcpath, nil
